/**
 * R'Key Prod - Widget Integration
 * Script d'intégration pour sites externes (Billetterie, Profil DJ, etc.)
 * Usage: Ajoutez ce script et un lien avec la classe "rkey-widget-integration"
 * Le href du lien détermine quelle page widget charger (avec ses paramètres)
 */
(function() {
    'use strict';
    
    var WIDGET_CLASS = 'rkey-widget-integration';
    
    // Fonction pour créer l'iframe
    function createWidget(element) {
        // Utiliser le href de l'élément pour charger le bon widget avec ses paramètres
        var widgetUrl = element.getAttribute('href');
        
        if (!widgetUrl) {
            console.error('R\'Key Widget: href manquant sur l\'élément');
            return;
        }
        
        var container = document.createElement('div');
        container.style.cssText = 'width:100%;max-width:100%;overflow:hidden;';
        
        var iframe = document.createElement('iframe');
        iframe.src = widgetUrl;  // Utilise l'URL du href (avec ?type=hypnose si présent)
        iframe.style.cssText = 'width:100%;border:none;overflow:hidden;';
        iframe.setAttribute('scrolling', 'no');
        iframe.setAttribute('frameborder', '0');
        iframe.setAttribute('allowtransparency', 'true');
        
        // Hauteur par défaut ou personnalisée
        var height = element.getAttribute('data-height') || '800';
        iframe.style.height = height + 'px';
        
        // Largeur
        var width = element.getAttribute('data-width') || '100%';
        container.style.width = width;
        
        // Gestion du redimensionnement automatique
        if (element.getAttribute('data-resize') === '1') {
            window.addEventListener('message', function(event) {
                if (event.data && event.data.type === 'rkey-widget-resize') {
                    iframe.style.height = event.data.height + 'px';
                }
            });
        }
        
        container.appendChild(iframe);
        
        // Remplacer le lien par l'iframe
        element.parentNode.replaceChild(container, element);
    }
    
    // Initialisation
    function init() {
        var widgets = document.getElementsByClassName(WIDGET_CLASS);
        // Convertir en tableau car la collection est modifiée pendant l'itération
        var widgetsArray = Array.prototype.slice.call(widgets);
        
        for (var i = 0; i < widgetsArray.length; i++) {
            createWidget(widgetsArray[i]);
        }
    }
    
    // Exécuter quand le DOM est prêt
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', init);
    } else {
        init();
    }
})();
